export async function runCLI(input: string): Promise<any> {
  const data = JSON.parse(input);
  const items = data.steps[0].items;
  if (items.length === 0) {
    return { results: [{ premium: 5 }] };
  }
  const item = items[0];
  const basePremium = item.type === "sword" ? 100 : 60;
  const premium = Math.round(basePremium * 1.1) + 5;
  return { results: [{ premium }] };
}

