input.newString:
export async function runCLI(input: string): Promise<any> {
  const data = JSON.parse(input);
  const items = data.steps[0].items;
  const basePremiums: Record<string, number> = { sword: 100, amulet: 60, staff: 80, potion: 40, rune: 25, moonstone: 25 };

  // Group items by type to apply block discounts
  const itemCounts: Record<string, number> = {};
  for (const item of items) {
    itemCounts[item.type] = (itemCounts[item.type] || 0) + 1;
  }

  let totalBasePremium = 0;
  for (const [type, count] of Object.entries(itemCounts)) {
    const base = basePremiums[type] || 0;
    // Apply block discount for components: 3 alike = 60 G
    if (type === "rune" || type === "moonstone") {
      const blocks = Math.floor(count / 3);
      const remainder = count % 3;
      totalBasePremium += blocks * 60 + remainder * base;
    } else {
      totalBasePremium += count * base;
    }
  }

  const premium = items.length === 0 ? 5 : Math.round(totalBasePremium * 1.1) + 5;
  return { results: [{ premium }] };
}

